@classmethod
def _from_persist_path_utf8(cls, persist_path, fs=None):
    if fs is None:
        fs = _fsspec.filesystem("file")
    with fs.open(persist_path, "r", encoding="utf-8") as f:
        data = json.loads(f.read())
    return cls.from_dict(data)

